parameters.functionCode:
// Art. 17 LFPIORPI — 14 actividades vulnerables
const UMA_DIARIO_2026 = 117.31;
const UMA_MENSUAL_2026 = 3568.94;

const ACTIVIDADES_VULNERABLES = {
  'I': { nombre: 'Juegos con apuestas', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'II': { nombre: 'Tarjetas de servicios', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'III': { nombre: 'Traslado o custodia de dinero', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'IV': { nombre: 'Blindaje de vehículos', umbral_aviso_umas: 2410, umbral_reporte_umas: null },
  'V': { nombre: 'Traslado de valores', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'VI': { nombre: 'Gestión de activos', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'VII': { nombre: 'Inmobiliaria', umbral_aviso_umas: 8025, umbral_reporte_umas: 16050 },
  'VIII': { nombre: 'Joyas, metales, arte', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'IX': { nombre: 'Vehículos', umbral_aviso_umas: 3210, umbral_reporte_umas: 6420 },
  'X': { nombre: 'Casas de cambio / divisas', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'XI': { nombre: 'Tarjetas de crédito / prepago', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'XII': { nombre: 'Fideicomisos', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'XIII': { nombre: 'Servicios notariales / fedatarios', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 },
  'XIV': { nombre: 'Servicios profesionales independientes', umbral_aviso_umas: 645, umbral_reporte_umas: 1500 }
};

const { actividad_clave, monto, rfc, nombre, es_pep } = $json;
const actividad = ACTIVIDADES_VULNERABLES[actividad_clave];

if (!actividad) {
  return [{ json: { error: 'Actividad no reconocida', actividad_clave } }];
}

const umas = monto / UMA_DIARIO_2026;
const supera_aviso = umas >= actividad.umbral_aviso_umas;
const supera_reporte = actividad.umbral_reporte_umas && umas >= actividad.umbral_reporte_umas;

let nivel_riesgo = 'bajo';
if (es_pep || supera_reporte) nivel_riesgo = 'alto';
else if (supera_aviso) nivel_riesgo = 'medio';

return [{
  json: {
    rfc, nombre, actividad_clave,
    actividad_nombre: actividad.nombre,
    monto, moneda: 'MXN',
    umas_equivalente: Math.round(umas),
    supera_umbral_aviso: supera_aviso,
    supera_umbral_reporte: supera_reporte,
    es_pep: !!es_pep,
    nivel_riesgo,
    requiere_reporte_uif: supera_reporte || es_pep,
    uma_diario_2026: UMA_DIARIO_2026
  }
}];

